1648: void Filter::onUpstreamHeaders(uint64_t response_code, Http::ResponseHeaderMapPtr&& headers,
1649:                                UpstreamRequest& upstream_request, bool end_stream) {
1650:   ENVOY_STREAM_LOG(debug, "upstream headers complete: end_stream={}", *callbacks_, end_stream);
1651: 
1652:   ASSERT(!host_selection_cancelable_);
1653: 
1654:   // When grpc-status appears in response headers, convert grpc-status to HTTP status code
1655:   // for outlier detection. This does not currently change any stats or logging and does not
1656:   // handle the case when an error grpc-status is sent as a trailer.
1657:   absl::optional<Grpc::Status::GrpcStatus> grpc_status;
1658:   uint64_t grpc_to_http_status = 0;
1659:   if (grpc_request_) {
1660:     grpc_status = Grpc::Common::getGrpcStatus(*headers);
1661:     if (grpc_status.has_value()) {
1662:       grpc_to_http_status = Grpc::Utility::grpcToHttpStatus(grpc_status.value());
1663:     }
1664:   }
1665: 
1666:   maybeProcessOrcaLoadReport(*headers, upstream_request);
1667: 
1668:   const uint64_t put_result_code = grpc_status.has_value() ? grpc_to_http_status : response_code;
1669:   upstream_request.upstreamHost()->outlierDetector().putResult(
1670:       put_result_code >= 500 ? Upstream::Outlier::Result::ExtOriginRequestFailed
1671:                              : Upstream::Outlier::Result::ExtOriginRequestSuccess,
1672:       put_result_code);
1673: 
1674:   if (headers->EnvoyImmediateHealthCheckFail() != nullptr) {
1675:     upstream_request.upstreamHost()->healthChecker().setUnhealthy(
1676:         Upstream::HealthCheckHostMonitor::UnhealthyType::ImmediateHealthCheckFail);
1677:   }
1678: 
1679:   bool could_not_retry = false;
1680: 
1681:   // Check if this upstream request was already retried, for instance after
1682:   // hitting a per try timeout. Don't retry it if we already have.
1683:   if (retry_state_) {
1684:     if (upstream_request.retried()) {
1685:       // We already retried this request (presumably for a per try timeout) so
1686:       // we definitely won't retry it again. Check if we would have retried it
1687:       // if we could.
1688:       bool retry_as_early_data; // Not going to be used as we are not retrying.
1689:       could_not_retry = retry_state_->wouldRetryFromHeaders(*headers, *downstream_headers_,
1690:                                                             retry_as_early_data) !=
1691:                         RetryState::RetryDecision::NoRetry;
1692:     } else {
1693:       const RetryStatus retry_status = retry_state_->shouldRetryHeaders(
1694:           *headers, *downstream_headers_,
1695:           [this, can_use_http3 = upstream_request.upstreamStreamOptions().can_use_http3_,
1696:            had_early_data = upstream_request.upstreamStreamOptions().can_send_early_data_](
1697:               bool disable_early_data) -> void {
1698:             doRetry((disable_early_data ? false : had_early_data), can_use_http3, TimeoutRetry::No);
1699:           });
1700:       if (retry_status == RetryStatus::Yes) {
1701:         runRetryOptionsPredicates(upstream_request);
1702:         pending_retries_++;
1703:         upstream_request.upstreamHost()->stats().rq_error_.inc();
1704:         Http::CodeStats& code_stats = httpContext().codeStats();
1705:         code_stats.chargeBasicResponseStat(cluster_->statsScope(), stats_.stat_names_.retry_,
1706:                                            static_cast<Http::Code>(response_code),
1707:                                            exclude_http_code_stats_);
1708: 
1709:         if (!end_stream || !upstream_request.encodeComplete()) {
1710:           upstream_request.resetStream();
1711:         }
1712:         auto request_ptr = upstream_request.removeFromList(upstream_requests_);
1713:         callbacks_->dispatcher().deferredDelete(std::move(request_ptr));
1714:         return;
1715:       } else if (retry_status == RetryStatus::NoOverflow) {
1716:         callbacks_->streamInfo().setResponseFlag(StreamInfo::CoreResponseFlag::UpstreamOverflow);
1717:         could_not_retry = true;
1718:       } else if (retry_status == RetryStatus::NoRetryLimitExceeded) {
1719:         callbacks_->streamInfo().setResponseFlag(
1720:             StreamInfo::CoreResponseFlag::UpstreamRetryLimitExceeded);
1721:         could_not_retry = true;
1722:       }
1723:     }
1724:   }
1725: 
1726:   if (route_entry_->internalRedirectPolicy().enabled() &&
1727:       route_entry_->internalRedirectPolicy().shouldRedirectForResponseCode(
1728:           static_cast<Http::Code>(response_code)) &&
1729:       setupRedirect(*headers)) {
1730:     return;
1731:     // If the redirect could not be handled, fail open and let it pass to the
1732:     // next downstream.
1733:   }
1734: 
1735:   // Check if we got a "bad" response, but there are still upstream requests in
1736:   // flight awaiting headers or scheduled retries. If so, exit to give them a
1737:   // chance to return before returning a response downstream.
1738:   if (could_not_retry && (numRequestsAwaitingHeaders() > 0 || pending_retries_ > 0)) {
1739:     upstream_request.upstreamHost()->stats().rq_error_.inc();
