1755:   // Only send upstream service time if we received the complete request and this is not a
1756:   // premature response.
1757:   if (DateUtil::timePointValid(downstream_request_complete_time_)) {
1758:     Event::Dispatcher& dispatcher = callbacks_->dispatcher();
1759:     MonotonicTime response_received_time = dispatcher.timeSource().monotonicTime();
1760:     std::chrono::milliseconds ms = std::chrono::duration_cast<std::chrono::milliseconds>(
1761:         response_received_time - downstream_request_complete_time_);
