709: Utility::PreparedLocalReplyPtr Utility::prepareLocalReply(const EncodeFunctions& encode_functions,
710:                                                           const LocalReplyData& local_reply_data) {
711:   Code response_code = local_reply_data.response_code_;
712:   std::string body_text(local_reply_data.body_text_);
713:   absl::string_view content_type(Headers::get().ContentTypeValues.Text);
714: 
715:   ResponseHeaderMapPtr response_headers{createHeaderMap<ResponseHeaderMapImpl>(
716:       {{Headers::get().Status, std::to_string(enumToInt(response_code))}})};
717: 
718:   if (encode_functions.modify_headers_) {
719:     encode_functions.modify_headers_(*response_headers);
720:   }
721:   bool has_custom_content_type = false;
722:   if (encode_functions.rewrite_) {
723:     std::string content_type_value = std::string(response_headers->getContentTypeValue());
724:     encode_functions.rewrite_(*response_headers, response_code, body_text, content_type);
725:     has_custom_content_type = (content_type_value != response_headers->getContentTypeValue());
726:   }
727: 
728:   if (local_reply_data.is_grpc_) {
729:     response_headers->setStatus(std::to_string(enumToInt(Code::OK)));
730:     response_headers->setReferenceContentType(Headers::get().ContentTypeValues.Grpc);
731: 
732:     if (response_headers->getGrpcStatusValue().empty()) {
733:       response_headers->setGrpcStatus(std::to_string(
734:           enumToInt(local_reply_data.grpc_status_
735:                         ? local_reply_data.grpc_status_.value()
736:                         : Grpc::Utility::httpToGrpcStatus(enumToInt(response_code)))));
737:     }
738: 
739:     if (!body_text.empty() && !local_reply_data.is_head_request_) {
740:       // TODO(dio): Probably it is worth to consider caching the encoded message based on gRPC
741:       // status.
742:       // JsonFormatter adds a '\n' at the end. For header value, it should be removed.
743:       // https://github.com/envoyproxy/envoy/blob/main/source/common/formatter/substitution_formatter.cc#L129
744:       if (content_type == Headers::get().ContentTypeValues.Json &&
745:           body_text[body_text.length() - 1] == '\n') {
746:         body_text = body_text.substr(0, body_text.length() - 1);
747:       }
748:       response_headers->setGrpcMessage(PercentEncoding::encode(body_text));
749:     }
750:     // The `modify_headers` function may have added content-length, remove it.
751:     response_headers->removeContentLength();
752: 
753:     // TODO(kbaichoo): In C++20 we will be able to use make_unique with
754:     // aggregate initialization.
755:     // NOLINTNEXTLINE(modernize-make-unique)
756:     return PreparedLocalReplyPtr(new PreparedLocalReply{
757:         local_reply_data.is_grpc_, local_reply_data.is_head_request_, std::move(response_headers),
758:         std::move(body_text), encode_functions.encode_headers_, encode_functions.encode_data_});
759:   }
760: 
761:   if (!body_text.empty()) {
762:     response_headers->setContentLength(body_text.size());
763:     // If the content-type is not set, set it.
764:     // Alternately if the `rewrite` function has changed body_text and the config didn't explicitly
765:     // set a content type header, set the content type to be based on the changed body.
766:     if (response_headers->ContentType() == nullptr ||
767:         (body_text != local_reply_data.body_text_ && !has_custom_content_type)) {
768:       response_headers->setReferenceContentType(content_type);
769:     }
770:   } else {
771:     response_headers->removeContentLength();
772:     response_headers->removeContentType();
773:   }
774: 
775:   // TODO(kbaichoo): In C++20 we will be able to use make_unique with
776:   // aggregate initialization.
777:   // NOLINTNEXTLINE(modernize-make-unique)
778:   return PreparedLocalReplyPtr(new PreparedLocalReply{
779:       local_reply_data.is_grpc_, local_reply_data.is_head_request_, std::move(response_headers),
780:       std::move(body_text), encode_functions.encode_headers_, encode_functions.encode_data_});
781: }
